def get_questions_by_persona(persona: str):
    return [q for q in QUESTION_BANK if q["persona"] == persona]


def get_questions_by_dimension(dimension: str):
    return [q for q in QUESTION_BANK if q["dimension"] == dimension]


def get_question_by_id(question_id: str):
    for q in QUESTION_BANK:
        if q["id"] == question_id:
            return q
    return None
